function getGeneFunction(gene) {
  return DB.gene_functions[gene.toUpperCase()] || "";
}

function getAcupointInfo(name) {
  const info = DB.acupoint_info[name] || {};
  if (!info.meridian) {
    for (const [key, val] of Object.entries(DB.acupoint_info)) {
      if (key.toUpperCase().includes(name.toUpperCase()) || name.toUpperCase().includes(key.toUpperCase())) {
        return val;
      }
    }
  }
  return info;
}

function getStats() {
  return DB.stats;
}

function getYearData() {
  return DB.year_data;
}

function getTopGenes(limit = 20) {
  return DB.top_genes.slice(0, limit);
}

function getTopAcupoints(limit = 20) {
  return DB.top_acupoints.slice(0, limit);
}

function getTopDiseases(limit = 15) {
  return DB.top_diseases.slice(0, limit);
}

function getAcupointList() {
  return DB.acupoint_list;
}

function getGeneList() {
  return DB.gene_list;
}

function getDiseaseList() {
  return DB.disease_list;
}

function getJournalStats(limit = 20) {
  return DB.journal_stats.slice(0, limit);
}

function queryAcupointGenes(acupointName) {
  if (!acupointName) return [];
  const aptPmids = new Set(DB.acupoint_pmids[acupointName] || []);
  if (!aptPmids.size) return [];

  const aptTotal = aptPmids.size;
  const geneCounts = {};
  for (const pmid of aptPmids) {
    const genes = DB.pmid_genes[pmid] || [];
    for (const g of genes) {
      geneCounts[g] = (geneCounts[g] || 0) + 1;
    }
  }

  const results = [];
  for (const [gene, cooccur] of Object.entries(geneCounts)) {
    const genePmids = new Set(DB.gene_pmids[gene] || []);
    const geneTotal = genePmids.size;
    const union = aptTotal + geneTotal - cooccur;
    const jaccard = union > 0 ? Math.round((cooccur / union) * 10000) / 10000 : 0;

    const commonPmids = [...aptPmids].filter(p => genePmids.has(p)).sort((a, b) => b - a).slice(0, 20);
    const articles = [];
    for (const pmid of commonPmids) {
      const art = DB.pmid_to_article[pmid];
      if (art) {
        articles.push({ pmid: art.pmid, title: art.title, year: art.year, doi: art.doi, journal: art.journal });
      }
    }

    results.push({
      gene, cooccur, jaccard, apt_total: aptTotal, gene_total: geneTotal,
      article_count: articles.length, articles,
      gene_function: getGeneFunction(gene)
    });
  }

  return results.sort((a, b) => b.cooccur - a.cooccur);
}

function queryGeneAcupoints(geneSymbol) {
  if (!geneSymbol) return [];
  const genePmids = new Set(DB.gene_pmids[geneSymbol] || []);
  if (!genePmids.size) return [];

  const geneTotal = genePmids.size;
  const aptCounts = {};
  for (const pmid of genePmids) {
    const apts = DB.pmid_acupoints[pmid] || [];
    for (const a of apts) {
      aptCounts[a.name] = (aptCounts[a.name] || 0) + 1;
    }
  }

  const results = [];
  for (const [acupoint, cooccur] of Object.entries(aptCounts)) {
    const aptPmids = new Set(DB.acupoint_pmids[acupoint] || []);
    const aptTotal = aptPmids.size;
    const union = geneTotal + aptTotal - cooccur;
    const jaccard = union > 0 ? Math.round((cooccur / union) * 10000) / 10000 : 0;

    const commonPmids = [...genePmids].filter(p => aptPmids.has(p)).sort((a, b) => b - a).slice(0, 20);
    const articles = [];
    for (const pmid of commonPmids) {
      const art = DB.pmid_to_article[pmid];
      if (art) {
        articles.push({ pmid: art.pmid, title: art.title, year: art.year, doi: art.doi, journal: art.journal });
      }
    }

    const aptRow = DB.acupoint_list.find(a => a.name_en === acupoint);
    const aptInfo = getAcupointInfo(acupoint);
    results.push({
      acupoint, name_cn: aptRow ? aptRow.name_cn : "", code: aptRow ? aptRow.code : "",
      cooccur, jaccard, gene_total: geneTotal, apt_total: aptTotal,
      article_count: articles.length, articles,
      meridian: aptInfo.meridian || "", apt_function: aptInfo.function || ""
    });
  }

  return results.sort((a, b) => b.cooccur - a.cooccur);
}

function getNetworkData(minCooccur = 2, acupointsFilter, genesFilter, diseaseFilter, limit = 300) {
  let net = DB.network_data.filter(n => n.count >= minCooccur);

  if (acupointsFilter && acupointsFilter.length) {
    net = net.filter(n => acupointsFilter.includes(n.acupoint));
  }
  if (genesFilter && genesFilter.length) {
    net = net.filter(n => genesFilter.includes(n.gene));
  }

  if (diseaseFilter) {
    const diseasePmids = new Set(DB.disease_pmids[diseaseFilter] || []);
    if (!diseasePmids.size) return [];
    const validPairs = new Set();
    for (const pmid of diseasePmids) {
      const apts = DB.pmid_acupoints[pmid] || [];
      const genes = DB.pmid_genes[pmid] || [];
      for (const a of apts) {
        for (const g of genes) {
          validPairs.add(`${a.name}::${g}`);
        }
      }
    }
    net = net.filter(n => validPairs.has(`${n.acupoint}::${n.gene}`));
    if (acupointsFilter && acupointsFilter.length) {
      net = net.filter(n => acupointsFilter.includes(n.acupoint));
    }
    if (genesFilter && genesFilter.length) {
      net = net.filter(n => genesFilter.includes(n.gene));
    }
  }

  net.sort((a, b) => b.count - a.count);
  return net.slice(0, limit);
}

function getArticles(page = 1, perPage = 20, search = "") {
  let arts = DB.articles;
  if (search) {
    const s = search.toLowerCase();
    arts = arts.filter(a => (a.title && a.title.toLowerCase().includes(s)));
  }
  const total = arts.length;
  const start = (page - 1) * perPage;
  const pageArts = arts.slice(start, start + perPage);
  return {
    articles: pageArts.map(a => ({
      id: a.id, pmid: a.pmid, title: a.title, journal: a.journal,
      year: a.year, doi: a.doi, has_fulltext: a.has_fulltext
    })),
    total, page, per_page: perPage
  };
}

function getArticleDetail(articleId) {
  const art = DB.articles.find(a => a.id === articleId);
  if (!art) return null;
  const pmid = art.pmid;
  const full = DB.pmid_to_article[pmid] || {};
  return {
    id: art.id, pmid, doi: full.doi || "", title: full.title || art.title,
    abstract: full.abstract || "", journal: full.journal || art.journal,
    year: full.year || art.year, authors: full.authors || "",
    has_fulltext: full.has_fulltext || false,
    genes: DB.pmid_genes[pmid] || [],
    acupoints: DB.pmid_acupoints[pmid] || [],
    diseases: DB.pmid_diseases[pmid] || [],
  };
}

