// ========================================================================
// Worker 入口
// ========================================================================

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const query = url.searchParams;

    try {
      // API 路由
      if (path === "/api/stats") {
        return jsonResponse(getStats());
      }
      if (path === "/api/year_data") {
        return jsonResponse(getYearData());
      }
      if (path === "/api/top_genes") {
        return jsonResponse(getTopGenes(parseInt(query.get("limit") || "20")));
      }
      if (path === "/api/top_acupoints") {
        return jsonResponse(getTopAcupoints(parseInt(query.get("limit") || "20")));
      }
      if (path === "/api/top_diseases") {
        return jsonResponse(getTopDiseases(parseInt(query.get("limit") || "15")));
      }
      if (path === "/api/journal_stats") {
        return jsonResponse(getJournalStats(parseInt(query.get("limit") || "20")));
      }
      if (path === "/api/acupoint_list") {
        return jsonResponse(getAcupointList());
      }
      if (path === "/api/gene_list") {
        return jsonResponse(getGeneList());
      }
      if (path === "/api/disease_list") {
        return jsonResponse(getDiseaseList());
      }
      if (path === "/api/acupoint_genes") {
        return jsonResponse(queryAcupointGenes(query.get("acupoint") || ""));
      }
      if (path === "/api/gene_acupoints") {
        return jsonResponse(queryGeneAcupoints(query.get("gene") || ""));
      }
      if (path === "/api/network") {
        const minCooccur = parseInt(query.get("min_cooccur") || "2");
        const acupoints = query.get("acupoints") ? query.get("acupoints").split(",") : null;
        const genes = query.get("genes") ? query.get("genes").split(",") : null;
        const disease = query.get("disease") || null;
        return jsonResponse(getNetworkData(minCooccur, acupoints, genes, disease));
      }

      // 页面路由
      if (path === "/" || path === "/index.html") {
        return htmlResponse(renderIndex());
      }
      if (path === "/acupoint-query") {
        const apt = query.get("acupoint") || "";
        const results = apt ? queryAcupointGenes(apt) : [];
        return htmlResponse(renderAcupointQuery(apt, results));
      }
      if (path === "/gene-query") {
        const gene = query.get("gene") || "";
        const results = gene ? queryGeneAcupoints(gene) : [];
        return htmlResponse(renderGeneQuery(gene, results));
      }
      if (path === "/network") {
        return htmlResponse(renderNetwork());
      }
      if (path === "/articles") {
        const page = parseInt(query.get("page") || "1");
        const search = query.get("q") || "";
        const data = getArticles(page, 20, search);
        return htmlResponse(renderArticles(page, search, data));
      }
      if (path.startsWith("/article/")) {
        const id = parseInt(path.split("/")[2]);
        const article = getArticleDetail(id);
        return htmlResponse(renderArticleDetail(article));
      }
      if (path === "/about") {
        return htmlResponse(renderAbout());
      }

      return new Response("Not Found", { status: 404 });
    } catch (e) {
      return new Response("Error: " + e.message, { status: 500 });
    }
  }
};

function htmlResponse(html) {
  return new Response(html, {
    headers: { "Content-Type": "text/html; charset=utf-8" }
  });
}

function jsonResponse(data) {
  return new Response(JSON.stringify(data), {
    headers: { "Content-Type": "application/json; charset=utf-8" }
  });
}
